float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
  return(result);
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
							double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel)
{
    // OpenMP translation of pgain_kernel and associated logic
    // Variables
    int num = points->num;
    int dim = points->dim;
    int K = *numcenters;
    kmax++;
    float *work_mem_h = (float*)calloc(kmax*num, sizeof(float));
    float *gl_lower = (float*)calloc(kmax, sizeof(float));
    Point_Struct *p_h = (Point_Struct*)malloc(num * sizeof(Point_Struct));
    float gl_cost = 0.0f;

    // Build center_table: map center indices
    int count = 0;
    for(int i=0; i<num; i++){
        if(is_center[i]){
            center_table[i] = count++;
        }
    }

    // Prepare p_h from points
    for(int i=0; i<num; i++){
        p_h[i].weight = points->p[i].weight;
        p_h[i].assign = points->p[i].assign;
        p_h[i].cost = points->p[i].cost;
    }

    // Load coord: column major as in original code
    float *coord_h = (float*)malloc(num * dim * sizeof(float));
    for(int i=0; i<dim; i++){
        for(int j=0; j<num; j++){
            coord_h[i*num + j] = points->p[j].coord[i];
        }
    }

    // Initialize switch_membership and work_mem_h to zero
    memset(switch_membership, 0, num * sizeof(char));
    memset(work_mem_h, 0, (K+1)*num * sizeof(float));

    // OpenMP parallelization of pgain_kernel logic
    // We emulate the kernel with parallel for
    // The local memory coord_s is replaced by shared array with first thread copying data
    float *coord_s = (float*)malloc(dim * sizeof(float));
#pragma omp parallel shared(coord_s, switch_membership, work_mem_h)
    {
        int thread_id;
#pragma omp for schedule(static)
        for(thread_id=0; thread_id<num; thread_id++) {
            // First thread copies coord_s
            if(thread_id == 0) {
                for(int i=0; i<dim; i++) {
                    coord_s[i] = coord_h[i*num + x];
                }
            }
#pragma omp barrier
            float x_cost = 0.0f;
            for(int i=0; i<dim; i++){
                float diff = coord_h[i*num + thread_id] - coord_s[i];
                x_cost += diff*diff;
            }
            x_cost = x_cost * p_h[thread_id].weight;

            float current_cost = p_h[thread_id].cost;

            int base = thread_id*(K+1);

            if(x_cost < current_cost){
                switch_membership[thread_id] = '1';
                int addr_1 = base + K;
                work_mem_h[addr_1] = x_cost - current_cost;
            } else {
                int assign = p_h[thread_id].assign;
                int addr_2 = base + center_table[assign];
#pragma omp atomic
                work_mem_h[addr_2] += current_cost - x_cost;
            }
        }
#pragma omp barrier
    }
    free(coord_s);
    free(coord_h);

    gl_cost = z;

    int numclose = 0;
    // Compute gl_lower and update gl_cost
    for(int i=0; i<num; i++){
        if(is_center[i]){
            float low = z;
            int center_idx = center_table[i];
            for(int j=0; j<num; j++){
                low += work_mem_h[j*(K+1) + center_idx];
            }
            gl_lower[center_idx] = low;
            if(low > 0){
                numclose++;
                work_mem_h[i*(K+1) + K] -= low;
            }
        }
    }
    for(int i=0; i<num; i++){
        gl_cost += work_mem_h[i*(K+1) + K];
    }

    if(gl_cost < 0){
        // Update points assignments and costs
        for(int i=0; i<num; i++){
            bool close_center = (gl_lower[center_table[points->p[i].assign]] > 0);
            if((switch_membership[i] == '1') || close_center){
                points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
                points->p[i].assign = x;
            }
        }
        for(int i=0; i<num; i++){
            if(is_center[i] && gl_lower[center_table[i]] > 0){
                is_center[i] = false;
            }
        }
        is_center[x] = true;
        *numcenters = *numcenters + 1 - numclose;
    } else {
        gl_cost = 0;
    }

    free(work_mem_h);
    free(gl_lower);
    free(p_h);

    return -gl_cost;
}

